            display: flex;
            justify-content: space-between;
            align-items: center;
        }

        .modal-title {
            font-size: 20px;
            font-weight: 600;
            color: #333;
        }

        .close-btn {
            background: none;
            border: none;
            font-size: 24px;
            cursor: pointer;
            color: #888;
            transition: color 0.2s;
        }

        .close-btn:hover {
            color: #ff6b6b;
        }

        .modal-body {
            padding: 20px;
            color: #555;
            line-height: 1.6;
        }
    </style>
</head>
<body>
    <div class="container">
        <button class="open-btn" onclick="openModal()">Open Modal</button>
    </div>

    <div class="modal-overlay" id="modalOverlay">
        <div class="modal" id="modal">
            <div class="modal-header">
                <h2 class="modal-title">Draggable Modal</h2>
                <button class="close-btn" onclick="closeModal()">&times;</button>
            </div>
            <div class="modal-body">
                <p>This is a draggable modal window with a blurred background effect. You can drag me around by clicking and holding the header!</p>
            </div>
        </div>
    </div>

    <script>
        const modalOverlay = document.getElementById('modalOverlay');
        const modal = document.getElementById('modal');
        let isDragging = false;
        let currentX;
        let currentY;
        let initialX;
        let initialY;

        function openModal() {
            modalOverlay.style.display = 'flex';
            // Center the modal initially
            positionModalAtCenter();
        }

        function closeModal() {
            modalOverlay.style.display = 'none';
        }

        function positionModalAtCenter() {
            const windowWidth = window.innerWidth;
            const windowHeight = window.innerHeight;
            const modalWidth = modal.offsetWidth;
            const modalHeight = modal.offsetHeight;

            modal.style.left = `${(windowWidth - modalWidth) / 2}px`;
            modal.style.top = `${(windowHeight - modalHeight) / 2}px`;
        }

        modal.addEventListener('mousedown', startDragging);
        document.addEventListener('mousemove', drag);
        document.addEventListener('mouseup', stopDragging);

        function startDragging(e) {
            initialX = e.clientX - currentX;
            initialY = e.clientY - currentY;
            isDragging = true;
        }

        function drag(e) {
            if (isDragging) {
                e.preventDefault();
                currentX = e.clientX - initialX;
                currentY = e.clientY - initialY;

                // Boundary checks
                const windowWidth = window.innerWidth;
                const windowHeight = window.innerHeight;
                const modalWidth = modal.offsetWidth;
                const modalHeight = modal.offsetHeight;

                currentX = Math.max(0, Math.min(currentX, windowWidth - modalWidth));
                currentY = Math.max(0, Math.min(currentY, windowHeight - modalHeight));

                modal.style.left = currentX + 'px';
                modal.style.top = currentY + 'px';
            }
        }

        function stopDragging() {
            isDragging = false;
        }

        // Initialize position variables
        currentX = parseInt(modal.style.left) || 0;
        currentY = parseInt(modal.style.top) || 0;

        // Close modal when clicking outside
        modalOverlay.addEventListener('click', (e) => {
            if (e.target === modalOverlay) {
                closeModal();
            }
        });

        // Recenter modal on window resize
        window.addEventListener('resize', positionModalAtCenter);
    </script>
</body>
</html>
```

### Features and Explanation:

1. **Modern Design**:
   - The modal uses a clean white background with subtle shadows and rounded corners.
   - The background gradient and blurred overlay (`backdrop-filter: blur()`) create a modern, professional look.
   - Smooth animations and hover effects enhance interactivity (button scaling, shadow effects).

2. **Draggable Functionality**:
   - The modal can be dragged by clicking and holding anywhere on it.
   - Boundary checks prevent the modal from being dragged outside the viewport.
   - Smooth dragging is achieved using `mousedown`, `mousemove`, and `mouseup` event listeners.

3. **Blurred Background**:
   - The overlay uses `backdrop-filter: blur(5px)` combined with a semi-transparent black background to create a frosted glass effect.
   - This effect applies only when the modal is open and enhances focus on the modal content.

4. **Responsive Behavior**:
   - The modal width is set to `400px` with `max-width: 90%` to ensure it fits on smaller screens.
   - The modal automatically re-centers on window resize.

5. **Interactivity**:
   - Clicking the "Open Modal" button shows the modal centered on the screen.
   - Clicking the "×" button or outside the modal closes it.
   - Hover effects on buttons provide visual feedback.

6. **Single File Structure**:
   - HTML, CSS, and JavaScript are combined in one file for simplicity and ease of use.
   - The code is well-commented and organized for readability.

