                <span></span>
                <span></span>
                <span></span>
            </div>
        </div>
    </nav>

    <!-- Content -->
    <div class="content">
        <h1>Scroll to See the Effect</h1>
        <p>Lorem ipsum dolor sit amet, consectetur adipiscing elit. Sed do eiusmod tempor incididunt ut labore et dolore magna aliqua. Ut enim ad minim veniam, quis nostrud exercitation ullamco laboris nisi ut aliquip ex ea commodo consequat.</p>
        <!-- Add more content for scrolling -->
        <div style="height: 1500px; margin-top: 20px;">
            <p>Scroll down to see the navbar hide, and scroll up to see it reappear!</p>
        </div>
    </div>

    <script>
        // Navbar Scroll Behavior
        let lastScrollTop = 0;
        const navbar = document.querySelector('.navbar');
        const minScroll = 200; // Minimum scroll before hiding starts

        window.addEventListener('scroll', function() {
            let currentScrollTop = window.pageYOffset || document.documentElement.scrollTop;

            // Scroll Down - Hide Navbar
            if (currentScrollTop > lastScrollTop && currentScrollTop > minScroll) {
                navbar.classList.add('hidden');
            }
            // Scroll Up - Show Navbar
            else if (currentScrollTop < lastScrollTop) {
                navbar.classList.remove('hidden');
            }
            lastScrollTop = currentScrollTop <= 0 ? 0 : currentScrollTop;
        });

        // Hamburger Menu Toggle
        const hamburger = document.querySelector('.hamburger');
        const navLinks = document.querySelector('.nav-links');

        hamburger.addEventListener('click', function() {
            navLinks.classList.toggle('active');
        });

        // Close mobile menu when clicking a link
        const navItems = document.querySelectorAll('.nav-links a');
        navItems.forEach(item => {
            item.addEventListener('click', function() {
                navLinks.classList.remove('active');
            });
        });
    </script>
</body>
</html>
```

### Features and Design Explanation:

1. **Responsive Design**:
