    <div class="slider-container">
        <div class="slides">
            <div class="slide">
                <img src="https://picsum.photos/800/500?random=1" alt="Slide 1">
                <div class="caption">Beautiful Landscape 1</div>
            </div>
            <div class="slide">
                <img src="https://picsum.photos/800/500?random=2" alt="Slide 2">
                <div class="caption">Beautiful Landscape 2</div>
            </div>
            <div class="slide">
                <img src="https://picsum.photos/800/500?random=3" alt="Slide 3">
                <div class="caption">Beautiful Landscape 3</div>
            </div>
        </div>
        <button class="arrow left">&larr;</button>
        <button class="arrow right">&rarr;</button>
        <div class="dots"></div>
    </div>

    <script>
        class Slider {
            constructor() {
                this.slides = document.querySelector('.slides');
                this.slideElements = document.querySelectorAll('.slide');
                this.leftArrow = document.querySelector('.arrow.left');
                this.rightArrow = document.querySelector('.arrow.right');
                this.dotsContainer = document.querySelector('.dots');
                this.currentIndex = 0;
                this.totalSlides = this.slideElements.length;
                this.autoSlideInterval = null;
                this.autoSlideDelay = 5000; // 5 seconds

                this.initialize();
            }

            initialize() {
                // Create dots
                this.createDots();
                // Set initial state
                this.updateSlider();
                // Start auto-sliding
                this.startAutoSlide();
                // Add event listeners
                this.addEventListeners();
            }

            createDots() {
                for (let i = 0; i < this.totalSlides; i++) {
                    const dot = document.createElement('div');
                    dot.classList.add('dot');
                    if (i === 0) dot.classList.add('active');
                    dot.dataset.index = i;
                    this.dotsContainer.appendChild(dot);
                }
            }

            updateSlider() {
                // Update slide position
                this.slides.style.transform = `translateX(${-this.currentIndex * 100}%)`;
                // Update active dot
                const dots = document.querySelectorAll('.dot');
                dots.forEach((dot, index) => {
                    dot.classList.toggle('active', index === this.currentIndex);
                });
            }

            goToSlide(index) {
                this.currentIndex = index;
                if (this.currentIndex < 0) {
                    this.currentIndex = this.totalSlides - 1;
                } else if (this.currentIndex >= this.totalSlides) {
                    this.currentIndex = 0;
                }
                this.updateSlider();
            }

            nextSlide() {
                this.goToSlide(this.currentIndex + 1);
            }

            prevSlide() {
                this.goToSlide(this.currentIndex - 1);
            }

            startAutoSlide() {
                this.autoSlideInterval = setInterval(() => {
                    this.nextSlide();
                }, this.autoSlideDelay);
            }

            stopAutoSlide() {
                clearInterval(this.autoSlideInterval);
            }

            addEventListeners() {
                this.leftArrow.addEventListener('click', () => {
                    this.stopAutoSlide();
                    this.prevSlide();
                    this.startAutoSlide();
                });

                this.rightArrow.addEventListener('click', () => {
                    this.stopAutoSlide();
                    this.nextSlide();
                    this.startAutoSlide();
                });

                this.dotsContainer.addEventListener('click', (e) => {
                    if (e.target.classList.contains('dot')) {
                        this.stopAutoSlide();
                        this.goToSlide(parseInt(e.target.dataset.index));
                        this.startAutoSlide();
                    }
                });

                // Pause auto-slide on hover
                this.sliderContainer = document.querySelector('.slider-container');
                this.sliderContainer.addEventListener('mouseenter', () => {
                    this.stopAutoSlide();
                });

                this.sliderContainer.addEventListener('mouseleave', () => {
                    this.startAutoSlide();
                });
            }
        }

        // Initialize the slider
        document.addEventListener('DOMContentLoaded', () => {
            new Slider();
        });
    </script>
</body>
</html>
