            50% { transform: translateY(-5px); }
        }
        .bounce:hover {
            animation: bounce 0.5s ease;
        }
    </style>
</head>
<body class="bg-gray-100 font-sans">
    <!-- Trigger Button -->
    <div class="flex justify-center items-center h-screen">
        <button id="openModalBtn" class="px-6 py-3 bg-indigo-600 text-white rounded-lg shadow-lg hover:bg-indigo-700 transition-colors bounce">
            Subscribe to Newsletter
        </button>
    </div>

    <!-- Modal Overlay -->
    <div id="modalOverlay" class="modal-overlay fixed inset-0 bg-black bg-opacity-50 flex justify-center items-center hidden">
        <!-- Modal Content -->
        <div class="modal-content bg-white rounded-lg p-8 max-w-md w-full shadow-xl relative">
            <!-- Close Button -->
            <button id="closeModalBtn" class="close-btn absolute top-3 right-3 text-gray-500 hover:text-gray-700 text-3xl transition-transform">
                &times;
            </button>
            <!-- Modal Header -->
            <h2 class="text-3xl font-bold text-indigo-600 mb-4 text-center">Newsletter Subscription</h2>
            <p class="text-gray-600 mb-6 text-center">Stay updated with our latest news and offers!</p>
            <!-- Subscription Form -->
            <form id="newsletterForm" class="flex flex-col gap-4">
                <div>
                    <label for="email" class="block text-gray-700 font-medium mb-1">Email Address</label>
                    <input type="email" id="email" name="email" 
                        class="w-full px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent"
                        placeholder="Enter your email" required>
                </div>
                <button type="submit" 
                    class="px-4 py-2 bg-indigo-600 text-white rounded-lg shadow hover:bg-indigo-700 transition-colors">
                    Subscribe
                </button>
            </form>
            <!-- Success Message (hidden by default) -->
            <div id="successMessage" class="hidden text-green-600 mt-4 text-center">
                Thank you for subscribing!
            </div>
        </div>
    </div>

    <script>
        // Modal elements
        const modalOverlay = document.getElementById('modalOverlay');
        const openModalBtn = document.getElementById('openModalBtn');
        const closeModalBtn = document.getElementById('closeModalBtn');
        const newsletterForm = document.getElementById('newsletterForm');
        const successMessage = document.getElementById('successMessage');

        // Open modal
        openModalBtn.addEventListener('click', () => {
            modalOverlay.classList.remove('hidden');
            setTimeout(() => modalOverlay.classList.add('active'), 10);
        });

        // Close modal
        closeModalBtn.addEventListener('click', () => {
            modalOverlay.classList.remove('active');
            setTimeout(() => modalOverlay.classList.add('hidden'), 300);
        });

        // Close modal when clicking outside
        modalOverlay.addEventListener('click', (e) => {
            if (e.target === modalOverlay) {
                modalOverlay.classList.remove('active');
                setTimeout(() => modalOverlay.classList.add('hidden'), 300);
            }
        });

        // Handle form submission
        newsletterForm.addEventListener('submit', (e) => {
            e.preventDefault();
            const formData = new FormData(newsletterForm);
            const email = formData.get('email');

            // Here you would typically send the email to a server
            console.log('Subscribed email:', email);

            // Show success message and hide form
            newsletterForm.classList.add('hidden');
            successMessage.classList.remove('hidden');

            // Close modal after 2 seconds
            setTimeout(() => {
                modalOverlay.classList.remove('active');
                setTimeout(() => {
                    modalOverlay.classList.add('hidden');
                    // Reset form and message visibility for next time
                    newsletterForm.classList.remove('hidden');
                    successMessage.classList.add('hidden');
                    newsletterForm.reset();
                }, 300);
            }, 2000);
        });
    </script>
</body>
</html>
```

