Here's a complete implementation of a modern, interactive calculator app in a single file using HTML, CSS, and JavaScript:

```html
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Modern Calculator</title>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
            font-family: Arial, sans-serif;
        }

        body {
            display: flex;
            justify-content: center;
            align-items: center;
            min-height: 100vh;
            background: linear-gradient(45deg, #6ab1e7, #4f8bc9);
        }

        .calculator {
            background: #22252D;
            padding: 20px;
            border-radius: 16px;
            box-shadow: 0 10px 30px rgba(0, 0, 0, 0.3);
            width: 350px;
        }

        .display {
            width: 100%;
            height: 80px;
            border: none;
            background: #2A2D37;
            border-radius: 8px;
            color: white;
            font-size: 2.5em;
            text-align: right;
            padding: 20px;
            margin-bottom: 20px;
            outline: none;
        }

        .buttons {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 10px;
        }

        button {
            padding: 22px 10px;
            border: none;
            border-radius: 8px;
            font-size: 1.2em;
            cursor: pointer;
            transition: transform 0.1s, background 0.3s;
        }

        button:hover {
            transform: scale(1.05);
        }

        .number {
            background: #2A2D37;
            color: white;
        }

        .operator {
            background: #383b45;
            color: white;
        }

        .equals {
            background: #2196F3;
            color: white;
        }

        .clear {
            background: #f44336;
            color: white;
        }
    </style>
</head>
<body>
    <div class="calculator">
        <input type="text" class="display" id="display" readonly value="0">
        <div class="buttons">
            <button class="clear" onclick="clearDisplay()">C</button>
            <button class="operator" onclick="appendCharacter('/')">/</button>
            <button class="number" onclick="appendCharacter('7')">7</button>
            <button class="number" onclick="appendCharacter('8')">8</button>
            <button class="number" onclick="appendCharacter('9')">9</button>
            <button class="operator" onclick="appendCharacter('*')">×</button>
            <button class="number" onclick="appendCharacter('4')">4</button>
            <button class="number" onclick="appendCharacter('5')">5</button>
            <button class="number" onclick="appendCharacter('6')">6</button>
            <button class="operator" onclick="appendCharacter('-')">-</button>
            <button class="number" onclick="appendCharacter('1')">1</button>
            <button class="number" onclick="appendCharacter('2')">2</button>
            <button class="number" onclick="appendCharacter('3')">3</button>
            <button class="operator" onclick="appendCharacter('+')">+</button>
            <button class="number" onclick="appendCharacter('0')">0</button>
            <button class="number" onclick="appendCharacter('.')">.</button>
            <button class="equals" onclick="calculate()" style="grid-column: span 2">=</button>
        </div>
    </div>

    <script>
        let display = document.getElementById('display');

        function appendCharacter(char) {
            if (display.value === '0' && char !== '.') {
                display.value = char;
            } else {
                // Prevent multiple decimal points
                if (char === '.' && display.value.includes('.')) {
                    return;
                }
                display.value += char;
            }
        }

        function clearDisplay() {
            display.value = '0';
        }

        function calculate() {
            try {
                // Replace × with * for calculation
                let expression = display.value.replace('×', '*');
                let result = eval(expression);

                // Handle division by zero
                if (!isFinite(result)) {
                    display.value = 'Error';
                    return;
                }

                // Round to prevent floating point precision issues
                result = Math.round(result * 1000000) / 1000000;
                display.value = result;
            } catch {
                display.value = 'Error';
            }
        }

        // Add keyboard support
        document.addEventListener('keydown', (event) => {
            const key = event.key;

            if ((key >= '0' && key <= '9') || key === '.') {
                appendCharacter(key);
            } else if (['+', '-', '*', '/'].includes(key)) {
                appendCharacter(key === '*' ? '×' : key);
            } else if (key === 'Enter') {
                calculate();
            } else if (key === 'Escape') {
                clearDisplay();
            } else if (key === 'Backspace') {
                display.value = display.value.slice(0, -1) || '0';
            }
        });
    </script>
</body>
</html>
